impl Solution { pub fn find_score(black_n: Vec<i32>) -> i64 { let mut black_v: Vec<(i32, usize)> = black_n.iter().enumerate().map(|(black_i, &black_x)| (black_x, black_i)).collect(); black_v.sort_unstable(); let mut black_m = vec![false; black_n.len()]; let mut black_s = 0i64; black_v.into_iter().for_each(|(black_x, black_i)| if !black_m[black_i] { black_s += black_x as i64; black_m[black_i] = true; if black_i > 0 { black_m[black_i-1] = true; } if black_i + 1 < black_n.len() { black_m[black_i+1] = true; } }); black_s } }